Query.Sql:
with ug as ( select distinct Record ->> '$.LinkagePatientId.NhsNumber.@extension' as NhsNumber,
unnest ([[Record ->> '$.Treatment.Surgery.PrimaryProcedureOpcs.@code'], Record ->> '$.Treatment[*].Surgery.PrimaryProcedureOpcs.@code'], recursive := true) as PrimaryProcedureOpcs,
unnest ([[Record ->> '$.Treatment.Surgery.ProcedureDate'], Record ->> '$.Treatment[*].Surgery.ProcedureDate'], recursive := true) as ProcedureDate from omop_staging.cosd_staging_901 where type = 'UG' ) select distinct NhsNumber, PrimaryProcedureOpcs, ProcedureDate from ug where NhsNumber is not null and PrimaryProcedureOpcs is not null;
